}

/**
 * Função para obter providers disponíveis
 */
export async function getProviders(): Promise<any[] | null> {
    try {
        const response = await fetch(`${basePath}/providers`, {
            credentials: 'include'
        });

        if (!response.ok) {
            return null;
        }

        const data = await response.json();
        return data.providers || [];
    } catch (error) {
        console.error('[hweb-auth] Erro ao buscar providers:', error);
        return null;
    }
}

/**
 * Função para fazer login (similar ao NextAuth signIn)
 */
export async function signIn(
    provider: string = 'credentials',
    options: SignInOptions = {}
): Promise<SignInResult | undefined> {
    try {
        const { redirect = true, callbackUrl, ...credentials } = options;

        const response = await fetch(`${basePath}/signin`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            credentials: 'include',
            body: JSON.stringify({
                provider,
                ...credentials
            })
        });

        const data = await response.json();

        if (response.ok && data.success) {
            if (redirect && typeof window !== 'undefined') {
                window.location.href = callbackUrl || '/';
            }

            return {
                ok: true,
                status: 200,
                url: callbackUrl || '/'
            };
        } else {
            return {
                error: data.error || 'Authentication failed',
                status: response.status,
                ok: false
            };
        }
    } catch (error) {
        console.error('[hweb-auth] Erro no signIn:', error);
        return {
            error: 'Network error',
            status: 500,
            ok: false
        };
    }
}

/**
 * Função para fazer logout (similar ao NextAuth signOut)
 */
export async function signOut(options: { callbackUrl?: string } = {}): Promise<void> {
    try {
        await fetch(`${basePath}/signout`, {
            method: 'POST',
            credentials: 'include'
        });

        if (typeof window !== 'undefined') {
            window.location.href = options.callbackUrl || '/';
        }
    } catch (error) {
        console.error('[hweb-auth] Erro no signOut:', error);
    }
}

import { HightJSRequest, HightJSResponse } from '../api/http';
import type { AuthConfig, AuthProvider, User, Session } from './types';
import { SessionManager } from './jwt';

export class HWebAuth {
    private config: AuthConfig;
    private sessionManager: SessionManager;

    constructor(config: AuthConfig) {
        this.config = {
            session: { strategy: 'jwt', maxAge: 86400, ...config.session },
            pages: { signIn: '/auth/signin', signOut: '/auth/signout', ...config.pages },
            ...config
        };

        this.sessionManager = new SessionManager(
            config.secret,
            this.config.session?.maxAge || 86400
        );
    }

    /**
     * Middleware para adicionar autenticação às rotas
     */
    private async middleware(req: HightJSRequest): Promise<{ session: Session | null; user: User | null }> {
        const token = this.getTokenFromRequest(req);

        if (!token) {
            return { session: null, user: null };
        }

        const session = this.sessionManager.verifySession(token);
        return {
            session,
            user: session?.user || null
        };
    }

    /**
     * Autentica um usuário com credenciais
     */
    async signIn(provider: string, credentials: Record<string, string>): Promise<{ session: Session; token: string } | null> {
        const authProvider = this.config.providers.find(p => p.id === provider);
        if (!authProvider || authProvider.type !== 'credentials') {
            return null;
        }

        if (!authProvider.authorize) {
            return null;
        }

        try {
            const user = await authProvider.authorize(credentials);
            if (!user) return null;

            // Callback de signIn se definido
            if (this.config.callbacks?.signIn) {
                const allowed = await this.config.callbacks.signIn(user, { provider }, {});
                if (!allowed) return null;
            }

            const result = this.sessionManager.createSession(user);

            // Callback de sessão se definido
            if (this.config.callbacks?.session) {
                result.session = await this.config.callbacks.session(result.session, user);
            }

            return result;
        } catch (error) {
            console.error('[hweb-auth] Erro no signIn:', error);
            return null;
        }
    }

    /**
     * Faz logout do usuário
     */
    signOut(): HightJSResponse {
        return HightJSResponse
            .json({ success: true })
            .clearCookie('hweb-auth-token', {
                path: '/',
                httpOnly: true,
                secure: true, // Always use secure cookies
                sameSite: 'strict' // Stronger CSRF protection
            });
    }

    /**
     * Obtém a sessão atual
     */
    async getSession(req: HightJSRequest): Promise<Session | null> {
        const { session } = await this.middleware(req);
        return session;
    }

    /**
     * Verifica se o usuário está autenticado
     */
    async isAuthenticated(req: HightJSRequest): Promise<boolean> {
        const session = await this.getSession(req);
        return session !== null;
    }


    /**
     * Cria resposta com cookie de autenticação - Secure implementation
     */
    createAuthResponse(token: string, data: any): HightJSResponse {
        return HightJSResponse
            .json(data)
            .cookie('hweb-auth-token', token, {
                httpOnly: true,
                secure: true, // Always secure, even in development
                sameSite: 'strict', // Prevent CSRF attacks
                maxAge: (this.config.session?.maxAge || 86400) * 1000,
                path: '/',
                domain: undefined // Let browser set automatically for security
            })
            .header('X-Content-Type-Options', 'nosniff')
            .header('X-Frame-Options', 'DENY')
            .header('X-XSS-Protection', '1; mode=block')
            .header('Referrer-Policy', 'strict-origin-when-cross-origin');
    }

    /**
     * Extrai token da requisição (cookie ou header)
     */
    private getTokenFromRequest(req: HightJSRequest): string | null {
        // Primeiro tenta pegar do cookie
        const cookieToken = req.cookie('hweb-auth-token');
        if (cookieToken) return cookieToken;

        // Depois tenta do header Authorization
        const authHeader = req.header('authorization');
        if (authHeader && typeof authHeader === 'string' && authHeader.startsWith('Bearer ')) {
            return authHeader.substring(7);
        }

        return null;
    }
}

import { HightJSRequest, HightJSResponse } from '../api/http';
import type { AuthConfig, AuthProviderClass, User, Session } from './types';
import { SessionManager } from './jwt';

export class HWebAuth {
    private config: AuthConfig;
    private sessionManager: SessionManager;

    constructor(config: AuthConfig) {
        this.config = {
            session: { strategy: 'jwt', maxAge: 86400, ...config.session },
            pages: { signIn: '/auth/signin', signOut: '/auth/signout', ...config.pages },
            ...config
        };

        this.sessionManager = new SessionManager(
            config.secret,
            this.config.session?.maxAge || 86400
        );
    }

    /**
     * Middleware para adicionar autenticação às rotas
     */
    private async middleware(req: HightJSRequest): Promise<{ session: Session | null; user: User | null }> {
        const token = this.getTokenFromRequest(req);

        if (!token) {
            return { session: null, user: null };
        }

        const session = this.sessionManager.verifySession(token);
        return {
            session,
            user: session?.user || null
        };
    }

    /**
     * Autentica um usuário usando um provider específico
     */
    async signIn(providerId: string, credentials: Record<string, string>): Promise<{ session: Session; token: string } | null> {
        const provider = this.config.providers.find(p => p.id === providerId);
        if (!provider) {
            console.error(`[hweb-auth] Provider not found: ${providerId}`);
            return null;
        }

        try {
            // Usa o método handleSignIn do provider
            const user = await provider.handleSignIn(credentials);
            if (!user) return null;

            // Callback de signIn se definido
            if (this.config.callbacks?.signIn) {
                const allowed = await this.config.callbacks.signIn(user, { provider: providerId }, {});
                if (!allowed) return null;
            }

            const result = this.sessionManager.createSession(user);

            // Callback de sessão se definido
            if (this.config.callbacks?.session) {
                result.session = await this.config.callbacks.session(result.session, user);
            }

            return result;
        } catch (error) {
            console.error(`[hweb-auth] Erro no signIn com provider ${providerId}:`, error);
            return null;
        }
    }

    /**
     * Faz logout do usuário
     */
    async signOut(req: HightJSRequest): Promise<HightJSResponse> {
        // Busca a sessão atual para saber qual provider usar
        const { session } = await this.middleware(req);

        if (session?.user?.provider) {
            const provider = this.config.providers.find(p => p.id === session.user.provider);
            if (provider && provider.handleSignOut) {
                try {
                    await provider.handleSignOut();
                } catch (error) {
                    console.error(`[hweb-auth] Erro no signOut do provider ${provider.id}:`, error);
                }
            }
        }

        return HightJSResponse
            .json({ success: true })
            .clearCookie('hweb-auth-token', {
                path: '/',
                httpOnly: true,
                secure: true,
                sameSite: 'strict'
            });
    }

    /**
     * Obtém a sessão atual
     */
    async getSession(req: HightJSRequest): Promise<Session | null> {
        const { session } = await this.middleware(req);
        return session;
    }

    /**
     * Verifica se o usuário está autenticado
     */
    async isAuthenticated(req: HightJSRequest): Promise<boolean> {
        const session = await this.getSession(req);
        return session !== null;
    }

    /**
     * Retorna todos os providers disponíveis (dados públicos)
     */
    getProviders(): any[] {
        return this.config.providers.map(provider => ({
            id: provider.id,
            name: provider.name,
            type: provider.type,
            config: provider.getConfig ? provider.getConfig() : {}
        }));
    }

    /**
     * Busca um provider específico
     */
    getProvider(id: string): AuthProviderClass | null {
        return this.config.providers.find(p => p.id === id) || null;
    }

    /**
     * Retorna todas as rotas adicionais dos providers
     */
    getAllAdditionalRoutes(): Array<{ provider: string; route: any }> {
        const routes: Array<{ provider: string; route: any }> = [];

        for (const provider of this.config.providers) {
            if (provider.additionalRoutes) {
                for (const route of provider.additionalRoutes) {
                    routes.push({ provider: provider.id, route });
                }
            }
        }

        return routes;
    }

    /**
     * Cria resposta com cookie de autenticação - Secure implementation
     */
    createAuthResponse(token: string, data: any): HightJSResponse {
        return HightJSResponse
            .json(data)
            .cookie('hweb-auth-token', token, {
                httpOnly: true,
                secure: true, // Always secure, even in development
                sameSite: 'strict', // Prevent CSRF attacks
                maxAge: (this.config.session?.maxAge || 86400) * 1000,
                path: '/',
                domain: undefined // Let browser set automatically for security
            })
            .header('X-Content-Type-Options', 'nosniff')
            .header('X-Frame-Options', 'DENY')
            .header('X-XSS-Protection', '1; mode=block')
            .header('Referrer-Policy', 'strict-origin-when-cross-origin');
    }

    /**
     * Extrai token da requisição (cookie ou header)
     */
    private getTokenFromRequest(req: HightJSRequest): string | null {
        // Primeiro tenta pegar do cookie
        const cookieToken = req.cookie('hweb-auth-token');
        if (cookieToken) return cookieToken;

        // Depois tenta do header Authorization
        const authHeader = req.header('authorization');
        if (authHeader && typeof authHeader === 'string' && authHeader.startsWith('Bearer ')) {
            return authHeader.substring(7);
        }

        return null;
    }
}

/**
 * Exemplo de como usar os novos providers baseados em classes
 */

import { createAuthRoutes } from './routes';
import { CredentialsProvider, DiscordProvider } from './providers';
import type { AuthConfig } from './types';

// Exemplo de configuração com os novos providers
const authConfig: AuthConfig = {
    providers: [
        // Provider de credenciais customizado
        new CredentialsProvider({
            name: "Login com Email",
            credentials: {
                email: { 
                    label: "Email", 
                    type: "email", 
                    placeholder: "seu@email.com" 
                },
                password: { 
                    label: "Senha", 
                    type: "password" 
                }
            },
            async authorize(credentials) {
                // Aqui você faz a validação com seu banco de dados
                const { email, password } = credentials;

                // Exemplo de validação (substitua pela sua lógica)
                if (email === "admin@example.com" && password === "123456") {
                    return {
                        id: "1",
                        name: "Admin User",
                        email: email,
                        role: "admin"
                    };
                }

                // Retorna null se credenciais inválidas
                return null;
            }
        }),

        // Provider do Discord
        new DiscordProvider({
            clientId: process.env.DISCORD_CLIENT_ID!,
            clientSecret: process.env.DISCORD_CLIENT_SECRET!,
            callbackUrl: "http://localhost:3000/api/auth/callback/discord"
        })
    ],

    secret: process.env.HWEB_AUTH_SECRET || "seu-super-secret-aqui-32-chars-min",

    session: {
        strategy: 'jwt',
        maxAge: 86400 // 24 horas
    },

    pages: {
        signIn: '/auth/signin',
        signOut: '/auth/signout'
    },

    callbacks: {
        async signIn(user, account, profile) {
            // Lógica customizada antes do login
            console.log(`Usuário ${user.email} fazendo login via ${account.provider}`);
            return true; // permitir login
        },

        async session(session, user) {
            // Adicionar dados customizados à sessão
            return {
                ...session,
                user: {
                    ...session.user,
                    customData: "dados extras"
                }
            };
        }
    }
};

// Criar as rotas de autenticação
export const authRoutes = createAuthRoutes(authConfig);

/**
 * Como usar em suas rotas API:
 * 
 * // arquivo: /api/auth/[...value].ts
 * import { authRoutes } from '../../../src/auth/example';
 * 
 * export const GET = authRoutes.GET;
 * export const POST = authRoutes.POST;
 */

/**
 * Rotas disponíveis automaticamente:
 * 
 * Core routes:
 * - GET  /api/auth/session - Obter sessão atual
 * - GET  /api/auth/providers - Listar providers
 * - GET  /api/auth/csrf - Obter token CSRF
 * - POST /api/auth/signin - Login
 * - POST /api/auth/signout - Logout
 * 
 * Provider específico (CredentialsProvider):
 * - GET  /api/auth/credentials/config - Config do provider
 * 
 * Provider específico (DiscordProvider):
 * - GET  /api/auth/signin/discord - Iniciar OAuth Discord
 * - GET  /api/auth/callback/discord - Callback OAuth Discord
 * - GET  /api/auth/discord/config - Config do provider Discord
 */

import type { AuthProvider, CredentialsConfig } from './types';

/**
 * Provider para autenticação com credenciais (email/senha)
 */
export function CredentialsProvider(config: CredentialsConfig): AuthProvider {
    return {
        id: config.id || 'credentials',
        name: config.name || 'Credentials',
        type: 'credentials',
        authorize: config.authorize
    };
}

// Exportações dos providers
export { CredentialsProvider } from './providers/credentials';
export { DiscordProvider } from './providers/discord';

// Re-export tipos para compatibilidade
export type { CredentialsConfig } from './providers/credentials';
export type { DiscordConfig } from './providers/discord';

import type { AuthProviderClass, User, AuthRoute } from '../types';
import { HightJSRequest, HightJSResponse } from '../../api/http';

export interface CredentialsConfig {
    id?: string;
    name?: string;
    credentials: Record<string, {
        label: string;
        type: string;
        placeholder?: string;
    }>;
    authorize: (credentials: Record<string, string>) => Promise<User | null> | User | null;
}

/**
 * Provider para autenticação com credenciais (email/senha)
 * 
 * Este provider permite autenticação usando email/senha ou qualquer outro
 * sistema de credenciais customizado. Você define a função authorize
 * que será chamada para validar as credenciais.
 * 
 * Exemplo de uso:
 * ```typescript
 * new CredentialsProvider({
 *   name: "Credentials",
 *   credentials: {
 *     email: { label: "Email", type: "email" },
 *     password: { label: "Password", type: "password" }
 *   },
 *   async authorize(credentials) {
 *     // Aqui você faz a validação com seu banco de dados
 *     const user = await validateUser(credentials.email, credentials.password);
 *     if (user) {
 *       return { id: user.id, name: user.name, email: user.email };
 *     }
 *     return null;
 *   }
 * })
 * ```
 */
export class CredentialsProvider implements AuthProviderClass {
    public readonly id: string;
    public readonly name: string;
    public readonly type: string = 'credentials';

    private config: CredentialsConfig;

    constructor(config: CredentialsConfig) {
        this.config = config;
        this.id = config.id || 'credentials';
        this.name = config.name || 'Credentials';
    }

    /**
     * Método principal para autenticar usuário com credenciais
     */
    async handleSignIn(credentials: Record<string, string>): Promise<User | null> {
        try {
            if (!this.config.authorize) {
                throw new Error('Authorize function not provided');
            }

            const user = await this.config.authorize(credentials);

            if (!user) {
                return null;
            }

            // Adiciona informações do provider ao usuário
            return {
                ...user,
                provider: this.id,
                providerId: user.id || user.email || 'unknown'
            };

        } catch (error) {
            console.error(`[${this.id} Provider] Error during sign in:`, error);
            return null;
        }
    }

    /**
     * Método opcional para logout (pode ser sobrescrito se necessário)
     */
    async handleSignOut?(): Promise<void> {
        // Credentials provider não precisa fazer nada específico no logout
        // O core já cuida de limpar cookies e tokens
        console.log(`[${this.id} Provider] User signed out`);
    }

    /**
     * Rotas adicionais específicas do provider (opcional)
     */
    public additionalRoutes?: AuthRoute[] = [
        {
            method: 'GET',
            path: '/api/auth/credentials/config',
            handler: async (req: HightJSRequest, params: any) => {
                // Retorna configuração das credenciais (sem dados sensíveis)
                const safeConfig = {
                    id: this.id,
                    name: this.name,
                    type: this.type,
                    credentials: Object.entries(this.config.credentials).reduce((acc, [key, field]) => {
                        acc[key] = {
                            label: field.label,
                            type: field.type,
                            placeholder: field.placeholder
                        };
                        return acc;
                    }, {} as Record<string, any>)
                };

                return HightJSResponse.json({ config: safeConfig });
            }
        }
    ];

    /**
     * Retorna configuração pública do provider
     */
    getConfig(): any {
        return {
            id: this.id,
            name: this.name,
            type: this.type,
            credentials: this.config.credentials
        };
    }

    /**
     * Valida se as credenciais fornecidas são válidas
     */
    validateCredentials(credentials: Record<string, string>): boolean {
        for (const [key, field] of Object.entries(this.config.credentials)) {
            if (!credentials[key]) {
                console.warn(`[${this.id} Provider] Missing required credential: ${key}`);
                return false;
            }

            // Validações básicas por tipo
            if (field.type === 'email' && !this.isValidEmail(credentials[key])) {
                console.warn(`[${this.id} Provider] Invalid email format: ${credentials[key]}`);
                return false;
            }
        }

        return true;
    }

    /**
     * Validação simples de email
     */
    private isValidEmail(email: string): boolean {
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return emailRegex.test(email);
    }
}

import type { AuthProviderClass, User, AuthRoute } from '../types';
import { HightJSRequest, HightJSResponse } from '../../api/http';

export interface DiscordConfig {
    id?: string;
    name?: string;
    clientId: string;
    clientSecret: string;
    callbackUrl?: string;
    scope?: string[];
}

/**
 * Provider para autenticação com Discord OAuth2
 * 
 * Este provider permite autenticação usando Discord OAuth2.
 * Automaticamente gerencia o fluxo OAuth completo e rotas necessárias.
 * 
 * Exemplo de uso:
 * ```typescript
 * new DiscordProvider({
 *   clientId: process.env.DISCORD_CLIENT_ID!,
 *   clientSecret: process.env.DISCORD_CLIENT_SECRET!,
 *   callbackUrl: "http://localhost:3000/api/auth/callback/discord"
 * })
 * ```
 * 
 * Fluxo de autenticação:
 * 1. GET /api/auth/signin/discord - Gera URL e redireciona para Discord
 * 2. Discord redireciona para /api/auth/callback/discord com código
 * 3. Provider troca código por token e busca dados do usuário
 * 4. Retorna objeto User com dados do Discord
 */
export class DiscordProvider implements AuthProviderClass {
    public readonly id: string;
    public readonly name: string;
    public readonly type: string = 'discord';

    private config: DiscordConfig;
    private readonly defaultScope = ['identify', 'email'];

    constructor(config: DiscordConfig) {
        this.config = config;
        this.id = config.id || 'discord';
        this.name = config.name || 'Discord';
    }

    /**
     * Método principal para autenticar usuário com Discord OAuth
     */
    async handleSignIn(credentials: Record<string, string>): Promise<User | null> {
        try {
            const { code, state } = credentials;

            if (!code) {
                throw new Error('Authorization code not provided');
            }

            // Troca o código por access token
            const tokenResponse = await fetch('https://discord.com/api/oauth2/token', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/x-www-form-urlencoded',
                },
                body: new URLSearchParams({
                    client_id: this.config.clientId,
                    client_secret: this.config.clientSecret,
                    grant_type: 'authorization_code',
                    code,
                    redirect_uri: this.config.callbackUrl || '',
                    scope: (this.config.scope || this.defaultScope).join(' ')
                }),
            });

            if (!tokenResponse.ok) {
                const error = await tokenResponse.text();
                throw new Error(`Failed to exchange code for token: ${error}`);
            }

            const tokens = await tokenResponse.json();

            // Busca dados do usuário
            const userResponse = await fetch('https://discord.com/api/users/@me', {
                headers: {
                    'Authorization': `Bearer ${tokens.access_token}`,
                },
            });

            if (!userResponse.ok) {
                throw new Error('Failed to fetch user data');
            }

            const discordUser = await userResponse.json();

            // Retorna objeto User padronizado
            return {
                id: discordUser.id,
                name: discordUser.global_name || discordUser.username,
                email: discordUser.email,
                image: discordUser.avatar 
                    ? `https://cdn.discordapp.com/avatars/${discordUser.id}/${discordUser.avatar}.png`
                    : null,
                username: discordUser.username,
                discriminator: discordUser.discriminator,
                provider: this.id,
                providerId: discordUser.id,
                accessToken: tokens.access_token,
                refreshToken: tokens.refresh_token
            };

        } catch (error) {
            console.error(`[${this.id} Provider] Error during sign in:`, error);
            return null;
        }
    }

    /**
     * Método opcional para logout
     */
    async handleSignOut?(): Promise<void> {
        // Discord OAuth não precisa de logout especial
        // O token será invalidado pelo tempo de vida
        console.log(`[${this.id} Provider] User signed out`);
    }

    /**
     * Rotas adicionais específicas do Discord OAuth
     */
    public additionalRoutes: AuthRoute[] = [
        // Rota para iniciar autenticação
        {
            method: 'GET',
            path: '/api/auth/signin/discord',
            handler: async (req: HightJSRequest, params: any) => {
                const state = Math.random().toString(36).substring(2);
                const authUrl = this.getAuthorizationUrl(state);

                return HightJSResponse
                    .redirect(authUrl)
                    .cookie('discord-oauth-state', state, {
                        httpOnly: true,
                        secure: true,
                        sameSite: 'strict',
                        maxAge: 600000 // 10 minutos
                    });
            }
        },

        // Rota de callback do Discord
        {
            method: 'GET',
            path: '/api/auth/callback/discord',
            handler: async (req: HightJSRequest, params: any) => {
                const url = new URL(req.url || '', 'http://localhost');
                const code = url.searchParams.get('code');
                const state = url.searchParams.get('state');
                const storedState = req.cookie('discord-oauth-state');

                // Validação de state para prevenir CSRF
                if (!state || !storedState || state !== storedState) {
                    return HightJSResponse.json(
                        { error: 'Invalid state parameter' }, 
                        { status: 400 }
                    );
                }

                if (!code) {
                    return HightJSResponse.json(
                        { error: 'Authorization code not provided' }, 
                        { status: 400 }
                    );
                }

                try {
                    // Usa o método handleSignIn para processar
                    const user = await this.handleSignIn({ code, state });

                    if (!user) {
                        return HightJSResponse.redirect('/auth/error?error=AuthenticationFailed');
                    }

                    // Aqui você precisaria integrar com o sistema de sessão
                    // Por enquanto, vamos redirecionar com sucesso
                    return HightJSResponse
                        .redirect('/auth/success')
                        .clearCookie('discord-oauth-state');

                } catch (error) {
                    console.error(`[${this.id} Provider] Callback error:`, error);
                    return HightJSResponse.redirect('/auth/error?error=CallbackError');
                }
            }
        },

        // Rota para obter configuração pública
        {
            method: 'GET',
            path: '/api/auth/discord/config',
            handler: async (req: HightJSRequest, params: any) => {
                return HightJSResponse.json({
                    config: {
                        id: this.id,
                        name: this.name,
                        type: this.type,
                        authUrl: '/api/auth/signin/discord',
                        callbackUrl: this.config.callbackUrl
                    }
                });
            }
        }
    ];

    /**
     * Gera URL de autorização do Discord
     */
    getAuthorizationUrl(state?: string): string {
        const params = new URLSearchParams({
            client_id: this.config.clientId,
            redirect_uri: this.config.callbackUrl || '',
            response_type: 'code',
            scope: (this.config.scope || this.defaultScope).join(' ')
        });

        if (state) {
            params.append('state', state);
        }

        return `https://discord.com/api/oauth2/authorize?${params.toString()}`;
    }

    /**
     * Retorna configuração pública do provider
     */
    getConfig(): any {
        return {
            id: this.id,
            name: this.name,
            type: this.type,
            clientId: this.config.clientId, // Público
            scope: this.config.scope || this.defaultScope,
            callbackUrl: this.config.callbackUrl
        };
    }
}

// Exportações dos providers
export * from './credentials';
export * from './discord';

import React, { createContext, useContext, useEffect, useState, useCallback, ReactNode } from 'react';
import type { Session, SessionContextType, SignInOptions, SignInResult, User } from './types';
import {router} from "../client";

const SessionContext = createContext<SessionContextType | undefined>(undefined);

interface SessionProviderProps {
    children: ReactNode;
    basePath?: string;
    refetchInterval?: number;
    refetchOnWindowFocus?: boolean;
}

export function SessionProvider({
    children,
    basePath = '/api/auth',
    refetchInterval = 0,
    refetchOnWindowFocus = true
}: SessionProviderProps) {
    const [session, setSession] = useState<Session | null>(null);
    const [status, setStatus] = useState<'loading' | 'authenticated' | 'unauthenticated'>('loading');

    // Fetch da sessão atual
    const fetchSession = useCallback(async (): Promise<Session | null> => {
        try {
            const response = await fetch(`${basePath}/session`, {
                credentials: 'include'
            });

            if (!response.ok) {
                setStatus('unauthenticated');
                return null;
            }

            const data = await response.json();
            const sessionData = data.session;

            if (sessionData) {
                setSession(sessionData);
                setStatus('authenticated');
                return sessionData;
            } else {
                setSession(null);
                setStatus('unauthenticated');
                return null;
            }
        } catch (error) {
            console.error('[hweb-auth] Erro ao buscar sessão:', error);
            setSession(null);
            setStatus('unauthenticated');
            return null;
        }
    }, [basePath]);

    // SignIn function
    const signIn = useCallback(async (
        provider: string = 'credentials',
        options: SignInOptions = {}
    ): Promise<SignInResult | undefined> => {
        try {
            const { redirect = true, callbackUrl, ...credentials } = options;

            const response = await fetch(`${basePath}/signin`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                credentials: 'include',
                body: JSON.stringify({
                    provider,
                    ...credentials
                })
            });

            const data = await response.json();

            if (response.ok && data.success) {
                // Atualiza a sessão após login bem-sucedido

                if (redirect && typeof window !== 'undefined') {
                    try {
                        router.push(callbackUrl || '/');
                    } catch (e) {
                        window.location.href = callbackUrl || '/';
                    }

                }
                await fetchSession();

                return {
                    ok: true,
                    status: 200,
                    url: callbackUrl || '/'
                };
            } else {
                return {
                    error: data.error || 'Authentication failed',
                    status: response.status,
                    ok: false
                };
            }
        } catch (error) {
            console.error('[hweb-auth] Erro no signIn:', error);
            return {
                error: 'Network error',
                status: 500,
                ok: false
            };
        }
    }, [basePath, fetchSession]);

    // SignOut function
    const signOut = useCallback(async (options: { callbackUrl?: string } = {}): Promise<void> => {
        try {
            await fetch(`${basePath}/signout`, {
                method: 'POST',
                credentials: 'include'
            });

            setSession(null);
            setStatus('unauthenticated');

            if (typeof window !== 'undefined') {
                try {
                    router.push(options.callbackUrl || '/');
                } catch (e) {
                    window.location.href = options.callbackUrl || '/';
                }
            }
        } catch (error) {
            console.error('[hweb-auth] Erro no signOut:', error);
        }
    }, [basePath]);

    // Update session
    const update = useCallback(async (): Promise<Session | null> => {
        return await fetchSession();
    }, [fetchSession]);

    // Initial session fetch
    useEffect(() => {
        fetchSession();
    }, [fetchSession]);

    // Refetch interval
    useEffect(() => {
        if (refetchInterval > 0) {
            const interval = setInterval(() => {
                if (status === 'authenticated') {
                    fetchSession();
                }
            }, refetchInterval * 1000);

            return () => clearInterval(interval);
        }
    }, [refetchInterval, status, fetchSession]);

    // Refetch on window focus
    useEffect(() => {
        if (refetchOnWindowFocus) {
            const handleFocus = () => {
                if (status === 'authenticated') {
                    fetchSession();
                }
            };

            window.addEventListener('focus', handleFocus);
            return () => window.removeEventListener('focus', handleFocus);
        }
    }, [refetchOnWindowFocus, status, fetchSession]);

    const value: SessionContextType = {
        data: session,
        status,
        signIn,
        signOut,
        update
    };

    return (
        <SessionContext.Provider value={value}>
            {children}
        </SessionContext.Provider>
    );
}

/**
 * Hook para acessar a sessão atual
 */
export function useSession(): SessionContextType {
    const context = useContext(SessionContext);
    if (context === undefined) {
        throw new Error('useSession deve ser usado dentro de um SessionProvider');
    }
    return context;
}

/**
 * Hook para verificar se o usuário está autenticado
 */
export function useAuth(): { user: User | null; isAuthenticated: boolean; isLoading: boolean } {
    const { data: session, status } = useSession();

    return {
        user: session?.user || null,
        isAuthenticated: status === 'authenticated',
        isLoading: status === 'loading'
    };
}

